m = int(input())
n = int(input())

matrix = []

for i in range(m):
    matrix.append([])
    row = input().split()

    for j in range(n):
        matrix[i].append(int(row[j]))

if len(matrix) >= 2:
    second_row = matrix[1]
    for element in second_row:
        print(element, end=' ')
    print()
else:
    print("The matrix does not have a second row.")
